import LocalAuthentication
import UIKit

class BiometricAuthManager {
    static let shared = BiometricAuthManager()
    
    private let context = LAContext()
    private let userDefaults = UserDefaults.standard
    private let biometricEnabledKey = "biometricAuthEnabled"
    private let isAuthenticatedKey = "isUserAuthenticated"
    
    private init() {}
    
    var isBiometricAuthEnabled: Bool {
        get {
            return userDefaults.bool(forKey: biometricEnabledKey)
        }
        set {
            userDefaults.set(newValue, forKey: biometricEnabledKey)
        }
    }
    
    var isUserAuthenticated: Bool {
        get {
            return userDefaults.bool(forKey: isAuthenticatedKey)
        }
        set {
            userDefaults.set(newValue, forKey: isAuthenticatedKey)
        }
    }
    
    func canUseBiometricAuthentication() -> (canUse: Bool, biometricType: LABiometryType, error: Error?) {
        var error: NSError?
        let canEvaluate = context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
        return (canEvaluate, context.biometryType, error)
    }
    
    func getBiometricTypeString() -> String {
        let biometricCheck = canUseBiometricAuthentication()
        switch biometricCheck.biometricType {
        case .faceID:
            return "Face ID"
        case .touchID:
            return "Touch ID"
        case .none:
            return "Biometric Authentication"
        @unknown default:
            return "Biometric Authentication"
        }
    }
    
    func authenticateWithBiometrics(reason: String? = nil, completion: @escaping (Bool, Error?) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Enter Password"
        context.localizedFallbackTitle = "Use Password"
        
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            completion(false, error)
            return
        }
        
        let authReason = reason ?? "Authenticate to access your account"
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: authReason) { success, error in
            DispatchQueue.main.async {
                completion(success, error)
            }
        }
    }
    
    func logout() {
        isUserAuthenticated = false
    }
    
    func markAsAuthenticated() {
        isUserAuthenticated = true
    }
}

