            biometricButton.isHidden = true
            enableBiometricLabel.isHidden = true
            enableBiometricSwitch.isHidden = true
        }
    }
    
    @objc private func loginButtonTapped() {
        guard let username = usernameTextField.text, !username.isEmpty,
              let password = passwordTextField.text, !password.isEmpty else {
            showAlert(title: "Error", message: "Please enter username and password")
            return
        }
        
        activityIndicator.startAnimating()
        loginButton.isEnabled = false
        
        authenticateWithCredentials(username: username, password: password) { [weak self] success in
            guard let self = self else { return }
            
            self.activityIndicator.stopAnimating()
            self.loginButton.isEnabled = true
            
            if success {
                BiometricAuthManager.shared.markAsAuthenticated()
                self.navigateToMainApp()
            } else {
                self.showAlert(title: "Login Failed", message: "Invalid username or password")
            }
        }
