    @objc private func biometricButtonTapped() {
        performBiometricAuthentication()
    }
    
    @objc private func biometricSwitchChanged() {
        BiometricAuthManager.shared.isBiometricAuthEnabled = enableBiometricSwitch.isOn
    }
    
    private func performBiometricAuthentication() {
        let biometricType = BiometricAuthManager.shared.getBiometricTypeString()
        
        BiometricAuthManager.shared.authenticateWithBiometrics(reason: "Authenticate to access your account") { [weak self] success, error in
            guard let self = self else { return }
            
            if success {
                BiometricAuthManager.shared.markAsAuthenticated()
                self.navigateToMainApp()
            } else {
                if let error = error as? LAError {
                    self.handleBiometricError(error, biometricType: biometricType)
                } else {
                    self.showRetryAlert(biometricType: biometricType)
                }
            }
        }
    }
    
    private func handleBiometricError(_ error: LAError, biometricType: String) {
        switch error.code {
        case .authenticationFailed:
            showRetryAlert(biometricType: biometricType)
        case .userCancel:
            break
        case .userFallback:
            usernameTextField.becomeFirstResponder()
        case .biometryNotAvailable:
            showAlert(title: "Not Available", message: "\(biometricType) is not available on this device")
        case .biometryNotEnrolled:
            showAlert(title: "Not Set Up", message: "Please set up \(biometricType) in Settings")
        case .biometryLockout:
            showAlert(title: "Locked Out", message: "\(biometricType) is locked. Please use your device passcode to unlock")
        default:
            showRetryAlert(biometricType: biometricType)
        }
    }
    
